import React from 'react';
import { AbsoluteFill, Img, useCurrentFrame, interpolate } from 'remotion';
import { PlacementBox } from '../../../lib/canvas';
import { parallaxSchema, type ParallaxProps } from './schema';

export { parallaxSchema, type ParallaxProps };

/**
 * Slow horizontal or vertical drift over an image — a lighter, no-zoom
 * complement to {@link KenBurns}. Used for backgrounds and b-roll where the
 * frame should feel alive without pulling focus.
 *
 * Intentionally **linear** (joins the linear-by-design club with KenBurns,
 * Marquee, Typewriter). At a 6-second scale a spring or ease would read as
 * the camera accelerating — wrong for parallax, which is steady throughout.
 *
 * @example
 * <Parallax src="/my-photo.jpg" direction="left" distance={40} />
 */
export const Parallax: React.FC<ParallaxProps> = ({
  src, delay, duration, direction, distance, placement,
}) => {
  const frame = useCurrentFrame();

  // Linear by design — constant drift, no acceleration. See KenBurns for the
  // same rationale at the same time scale.
  const progress = interpolate(frame - delay, [0, duration], [0, 1], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp',
  });

  const offset = progress * distance;

  // Axis + sign per direction. Left/up are negative translations; right/down
  // positive. The image rides scale(1.05) below so translation never reveals
  // empty edges of the canvas.
  const tx = direction === 'left' ? -offset : direction === 'right' ? offset : 0;
  const ty = direction === 'up' ? -offset : direction === 'down' ? offset : 0;

  const fillCanvas = placement === undefined;

  const img = (
    <Img
      src={src}
      style={{
        width: '100%',
        height: '100%',
        objectFit: 'cover',
        transform: `translate(${tx}px, ${ty}px) scale(1.05)`,
      }}
    />
  );

  // overflow: hidden is critical so the slightly-oversized image (scale 1.05)
  // doesn't bleed beyond the canvas bounds.
  if (fillCanvas) {
    return <AbsoluteFill style={{ overflow: 'hidden' }}>{img}</AbsoluteFill>;
  }

  return <PlacementBox placement={placement}>{img}</PlacementBox>;
};

import { z } from 'zod';
import { placementSchema } from '../../../lib/canvas-schemas';

/** Zod schema for {@link Parallax} props. */
export const parallaxSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('parallax').default('parallax'),
  /**
   * Image URL. The default is a stable Picsum seed so the playground render
   * is reproducible — supply your own `src` in real compositions.
   */
  src: z.string().default('https://picsum.photos/seed/onda-parallax/1920/1080'),
  /** Frames before the drift starts. */
  delay: z.number().int().min(0).default(0),
  /** Frames over which the drift completes. 180f ≈ 6s @ 30fps — parallax wants time. */
  duration: z.number().int().min(1).default(180),
  /** Drift direction. The image moves *toward* this edge as time advances. */
  direction: z.enum(['left', 'right', 'up', 'down']).default('left'),
  /** Total drift distance in pixels across `duration`. Keep restrained. */
  distance: z.number().default(40),
  /** Where on the canvas this sits. Region (`'center'`, `'upper-third'`, ...) or `{ x, y, anchor }` in 0..1 canvas fractions. When omitted, the component fills the entire canvas (default behavior). Coordinates may be negative or >1 for off-canvas. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link Parallax}. */
export type ParallaxProps = z.infer<typeof parallaxSchema>;

# Parallax

Slow horizontal or vertical drift over an image. A lighter, no-zoom complement to `KenBurns` — same constant cinematic feel, but used where the image is supposed to stay in the background and let other elements lead. Default: 40px drift over 6 seconds, leftward. The image rides a 1.05 scale so the translation never exposes the canvas edge.

## Props

| Name | Type | Default | Notes |
| --- | --- | --- | --- |
| `src` | `string` | `"https://picsum.photos/seed/onda-parallax/1920/1080"` | Image URL. The Picsum seed is for the playground only — supply your own `src` in real compositions. |
| `delay` | `integer ≥ 0` | `0` | Frames before the drift starts. |
| `duration` | `integer ≥ 1` | `180` | Frames the drift takes (6s @ 30fps). Parallax wants time; shortening reads as a swipe. |
| `direction` | `'left' \| 'right' \| 'up' \| 'down'` | `'left'` | The edge the image drifts *toward* as time advances. |
| `distance` | `number` | `40` | Total drift in pixels across `duration`. Keep restrained — large values stop reading as parallax. |
| `placement` | `Placement?` | – | Where on the canvas this sits. Region (`"center"`, `"upper-third"`, …) or `{ x, y, anchor }` in 0..1 canvas fractions. Coordinates may be negative or >1 for off-canvas. |

## Usage

```tsx
import { Composition } from 'remotion';
import { Parallax, parallaxSchema } from './components/onda/parallax/Parallax';

export const Root: React.FC = () => (
  <Composition
    id="ParallaxBackdrop"
    component={Parallax}
    durationInFrames={180}
    fps={30}
    width={1920}
    height={1080}
    schema={parallaxSchema}
    defaultProps={{
      src: 'https://picsum.photos/seed/onda-parallax/1920/1080',
      delay: 0,
      duration: 180,
      direction: 'left',
      distance: 40,
    }}
  />
);
```

## Motion notes

- **Linear by design.** `Parallax` joins the linear-by-design club with `KenBurns`, `Marquee`, and `Typewriter`. At a 6-second scale a spring or ease would read as the camera accelerating or settling — wrong for parallax, which is steady throughout. Restraint here means *constant* motion, not *eased* motion.
- **Restrained distance.** 40px over 6 seconds is a slow, ambient drift — the eye registers movement without feeling pushed. Going past ~120px starts to read as a pan or a swipe, not parallax.
- **`scale(1.05)` is intentional.** The image is rendered slightly oversized so that any translation up to `distance` still fills the canvas. Without it, drifting left would expose the right edge.
- **`<Img>` (not raw `<img>`).** The component uses Remotion's `<Img>`, which `delayRender`s until the image loads and auto-retries on failure. Safe for headless renders with network-sourced photos.
- **`overflow: hidden` on the `AbsoluteFill`** is critical — without it, the scaled-and-translated image bleeds beyond the canvas bounds.
- All `interpolate` calls clamp on both sides — the component is correct on frame 0 and on any frame past `delay + duration` (the image rests at the final offset).
